package com.spendwise.prototype.ui; import android.content.Intent; import android.os.Bundle; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import androidx.lifecycle.lifecycleScope; import com.spendwise.prototype.R; import com.spendwise.prototype.data.AppDatabase; import kotlinx.coroutines.launch; class LoginActivity:AppCompatActivity(){ override fun onCreate(b:Bundle?){ super.onCreate(b); setContentView(R.layout.activity_login); val db=AppDatabase.get(this); findViewById<Button>(R.id.btnLogin).setOnClickListener{ val u=findViewById<EditText>(R.id.etUser).text.toString(); val p=findViewById<EditText>(R.id.etPass).text.toString(); lifecycleScope.launch{ val a=db.userDao().login(u,p); if(a!=null){ startActivity(Intent(this@LoginActivity,MainActivity::class.java)); finish() } else Toast.makeText(this@LoginActivity,"Invalid",Toast.LENGTH_SHORT).show() } }; findViewById<TextView>(R.id.tvRegister).setOnClickListener{ startActivity(Intent(this,RegisterActivity::class.java)) } } }